sql:
SELECT song_id, title, popularity
FROM songs
WHERE popularity = (SELECT MAX(popularity) FROM songs);

SELECT SUM(duration_min) AS total_duration
FROM songs
WHERE artist_id = 'desired_artist_id';

external_knowledge:
- "primary genres" refer to genres marked with is_primary = 1;
- "beyond the millennium's dawn" refers to songs released after the year 2000;
- "keepers of digital keys" refers to users with admin privileges (is_admin = 1);
- "sung into the playlist's tapestry more than once" implies the song appears more than once in the playlist.

- "shining stars" metaphorically refers to the most popular songs;
- "music constellations" metaphorically represents the different genres of music;
- "top three in popularity" corresponds to the rank <= 3 condition in the SQL query.

sql:
SELECT title 
FROM songs 
WHERE duration_min = (SELECT MAX(duration_min) FROM songs);

SELECT DISTINCT title, artist_id
FROM songs
ORDER BY title ASC;

external_knowledge:
- "widely suggested" means songs that have been recommended more than 10 times; 
- "rock stars" refers to artists who perform rock music;
- "top three" means limiting the results to the first three entries based on the recommendation count.

sql:
SELECT title, genre
FROM songs
ORDER BY title;

SELECT a.name AS Artist
FROM artists a
JOIN songs s ON a.artist_id = s.artist_id
WHERE s.popularity = (
    SELECT MAX(popularity) FROM songs
);
